{
  "name": "todo-backend-api",
  "version": "1.0.0",
  "description": "RESTful CRUD API for Todo application using Express.js + SQLite",
  "main": "src/index.js",
  "scripts": {
    "start": "node src/index.js",
    "dev": "node src/index.js",
    "test": "jest --coverage",
    "test:watch": "jest --watch"
  },
  "keywords": ["express", "sqlite", "crud", "api", "todo"],
  "author": "Forge (Coder Agent)",
  "license": "MIT",
  "dependencies": {
    "better-sqlite3": "^9.4.3",
    "cors": "^2.8.5",
    "express": "^4.19.2",
    "uuid": "^9.0.1"
  },
  "devDependencies": {
    "jest": "^29.7.0",
    "supertest": "^6.3.4"
  }
}

const Database = require('better-sqlite3');
const path = require('path');

const dbPath = process.env.DB_PATH || path.join(__dirname, '../data/todo.db');

// 确保 data 目录存在
const fs = require('fs');
const dataDir = path.dirname(dbPath);
if (!fs.existsSync(dataDir)) {
  fs.mkdirSync(dataDir, { recursive: true });
}

const db = new Database(dbPath);

// 初始化数据库表
db.exec(`
  CREATE TABLE IF NOT EXISTS tasks (
    id TEXT PRIMARY KEY,
    title TEXT NOT NULL,
    description TEXT,
    status TEXT DEFAULT 'pending',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )
`);

// 创建更新时间触发器
db.exec(`
  CREATE TRIGGER IF NOT EXISTS update_tasks_updated_at
  AFTER UPDATE ON tasks
  BEGIN
    UPDATE tasks SET updated_at = CURRENT_TIMESTAMP WHERE id = OLD.id;
  END
`);

module.exports = db;

const db = require('../db');
const { v4: uuidv4 } = require('uuid');

class TaskModel {
  /**
   * 创建新任务
   * @param {Object} taskData - { title, description, status }
   * @returns {Object} 创建的任务对象
   */
  static create(taskData) {
    const { title, description = '', status = 'pending' } = taskData;
    const id = uuidv4();
    const created_at = new Date().toISOString();
    const updated_at = created_at;

    const stmt = db.prepare(`
      INSERT INTO tasks (id, title, description, status, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, ?)
    `);
    stmt.run(id, title, description, status, created_at, updated_at);

    return this.findById(id);
  }

  /**
   * 根据 ID 查找任务
   * @param {string} id
   * @returns {Object|null}
   */
  static findById(id) {
    const stmt = db.prepare('SELECT * FROM tasks WHERE id = ?');
    return stmt.get(id) || null;
  }

  /**
   * 查找所有任务
   * @param {Object} options - { status, limit, offset }
   * @returns {Array}
   */
  static findAll(options = {}) {
    let query = 'SELECT * FROM tasks';
    const params = [];

    if (options.status) {
      query += ' WHERE status = ?';
      params.push(options.status);
    }

    query += ' ORDER BY created_at DESC';

    if (options.limit) {
      query += ' LIMIT ?';
      params.push(options.limit);
      if (options.offset) {
        query += ' OFFSET ?';
        params.push(options.offset);
      }
    }

    const stmt = db.prepare(query);
    return stmt.all(...params);
  }

  /**
   * 更新任务
   * @param {string} id
   * @param {Object} updates - { title, description, status }
   * @returns {Object|null} 更新后的任务
   */
  static update(id, updates) {
    const allowedFields = ['title', 'description', 'status'];
    const fields = [];
    const values = [];

    for (const field of allowedFields) {
      if (updates[field] !== undefined) {
        fields.push(`${field} = ?`);
        values.push(updates[field]);
      }
    }

    if (fields.length === 0) {
      return this.findById(id);
    }

    // 不手动设置 updated_at，由数据库触发器自动更新
    values.push(id);

    const sql = `UPDATE tasks SET ${fields.join(', ')} WHERE id = ?`;
    const stmt = db.prepare(sql);
    const result = stmt.run(...values);

    if (result.changes === 0) {
      return null;
    }

    return this.findById(id);
  }

  /**
   * 删除任务
   * @param {string} id
   * @returns {boolean} 是否删除成功
   */
  static delete(id) {
    const stmt = db.prepare('DELETE FROM tasks WHERE id = ?');
    const result = stmt.run(id);
    return result.changes > 0;
  }

  /**
   * 统计任务数量
   * @returns {Object} { total, pending, in_progress, completed }
   */
  static count() {
    const total = db.prepare('SELECT COUNT(*) as count FROM tasks').get().count;
    const pending = db.prepare("SELECT COUNT(*) as count FROM tasks WHERE status = 'pending'").get().count;
    const in_progress = db.prepare("SELECT COUNT(*) as count FROM tasks WHERE status = 'in_progress'").get().count;
    const completed = db.prepare("SELECT COUNT(*) as count FROM tasks WHERE status = 'completed'").get().count;

    return { total, pending, in_progress, completed };
  }
}

module.exports = TaskModel;

const express = require('express');
const router = express.Router();
const TaskModel = require('../models/task');

/**
 * @route   GET /api/tasks
 * @desc    获取所有任务（支持按状态筛选）
 * @access  Public
 */
router.get('/', (req, res) => {
  try {
    const { status, limit, offset } = req.query;
    const tasks = TaskModel.findAll({
      status,
      limit: limit ? parseInt(limit) : undefined,
      offset: offset ? parseInt(offset) : undefined
    });
    res.json({
      success: true,
      data: tasks,
      meta: {
        count: tasks.length,
        timestamp: new Date().toISOString()
      }
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to fetch tasks',
      message: error.message
    });
  }
});

/**
 * @route   GET /api/tasks/:id
 * @desc    获取单个任务
 * @access  Public
 */
router.get('/:id', (req, res) => {
  try {
    const task = TaskModel.findById(req.params.id);
    if (!task) {
      return res.status(404).json({
        success: false,
        error: 'Task not found'
      });
    }
    res.json({
      success: true,
      data: task
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to fetch task',
      message: error.message
    });
  }
});

/**
 * @route   POST /api/tasks
 * @desc    创建新任务
 * @access  Public
 */
router.post('/', (req, res) => {
  try {
    const { title, description, status } = req.body;

    if (!title || typeof title !== 'string' || title.trim() === '') {
      return res.status(400).json({
        success: false,
        error: 'Title is required and must be a non-empty string'
      });
    }

    const task = TaskModel.create({
      title: title.trim(),
      description: description || '',
      status: status || 'pending'
    });

    res.status(201).json({
      success: true,
      data: task,
      message: 'Task created successfully'
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to create task',
      message: error.message
    });
  }
});

/**
 * @route   PUT /api/tasks/:id
 * @desc    更新任务
 * @access  Public
 */
router.put('/:id', (req, res) => {
  try {
    const { title, description, status } = req.body;
    const updates = {};

    if (title !== undefined) {
      if (typeof title !== 'string' || title.trim() === '') {
        return res.status(400).json({
          success: false,
          error: 'Title must be a non-empty string'
        });
      }
      updates.title = title.trim();
    }

    if (description !== undefined) {
      updates.description = description;
    }

    if (status !== undefined) {
      const validStatuses = ['pending', 'in_progress', 'completed'];
      if (!validStatuses.includes(status)) {
        return res.status(400).json({
          success: false,
          error: `Status must be one of: ${validStatuses.join(', ')}`
        });
      }
      updates.status = status;
    }

    const task = TaskModel.update(req.params.id, updates);
    if (!task) {
      return res.status(404).json({
        success: false,
        error: 'Task not found'
      });
    }

    res.json({
      success: true,
      data: task,
      message: 'Task updated successfully'
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to update task',
      message: error.message
    });
  }
});

/**
 * @route   DELETE /api/tasks/:id
 * @desc    删除任务
 * @access  Public
 */
router.delete('/:id', (req, res) => {
  try {
    const deleted = TaskModel.delete(req.params.id);
    if (!deleted) {
      return res.status(404).json({
        success: false,
        error: 'Task not found'
      });
    }
    res.json({
      success: true,
      message: 'Task deleted successfully'
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to delete task',
      message: error.message
    });
  }
});

/**
 * @route   GET /api/tasks/stats/count
 * @desc    获取任务统计
 * @access  Public
 */
router.get('/stats/count', (req, res) => {
  try {
    const stats = TaskModel.count();
    res.json({
      success: true,
      data: stats
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to get task statistics',
      message: error.message
    });
  }
});

module.exports = router;

const express = require('express');
const cors = require('cors');
const tasksRouter = require('./routes/tasks');

const app = express();
const PORT = process.env.PORT || 3000;

// 中间件
app.use(cors());
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// 健康检查端点
app.get('/health', (req, res) => {
  res.json({
    status: 'ok',
    timestamp: new Date().toISOString(),
    uptime: process.uptime()
  });
});

// API 路由
app.use('/api/tasks', tasksRouter);

// 404 处理
app.use((req, res) => {
  res.status(404).json({
    success: false,
    error: 'Route not found',
    path: req.path
  });
});

// 全局错误处理中间件
app.use((err, req, res, next) => {
  console.error('Error:', err);
  res.status(500).json({
    success: false,
    error: 'Internal server error',
    message: process.env.NODE_ENV === 'development' ? err.message : undefined
  });
});

// 启动服务器
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`🚀 Todo API server running on port ${PORT}`);
    console.log(`📋 API Base URL: http://localhost:${PORT}/api`);
    console.log(`📝 Docs: See README.md for API endpoints`);
  });
}

module.exports = app;

module.exports = {
  testEnvironment: 'node',
  coverageDirectory: 'coverage',
  collectCoverageFrom: [
    'src/**/*.js',
    '!src/index.js'
  ],
  testMatch: [
    '**/tests/**/*.test.js'
  ],
  verbose: true,
  testTimeout: 10000
};

const request = require('supertest');
const app = require('../src/index');
const TaskModel = require('../src/models/task');
const fs = require('fs');
const path = require('path');

// 在每个测试套件前后清理数据库
beforeEach(() => {
  // 重置数据库：删除并重建表
  const db = require('../src/db');
  db.exec('DELETE FROM tasks');
});

afterAll(() => {
  // 关闭数据库连接
  const db = require('../src/db');
  db.close();
});

describe('Todo API Endpoints', () => {
  describe('GET /health', () => {
    it('should return health status', async () => {
      const response = await request(app).get('/health');
      expect(response.status).toBe(200);
      expect(response.body).toHaveProperty('status', 'ok');
      expect(response.body).toHaveProperty('timestamp');
      expect(response.body).toHaveProperty('uptime');
    });
  });

  describe('POST /api/tasks', () => {
    it('should create a new task', async () => {
      const taskData = {
        title: 'Test Task',
        description: 'This is a test task',
        status: 'pending'
      };

      const response = await request(app)
        .post('/api/tasks')
        .send(taskData);

      expect(response.status).toBe(201);
      expect(response.body.success).toBe(true);
      expect(response.body.data).toHaveProperty('id');
      expect(response.body.data.title).toBe(taskData.title);
      expect(response.body.data.description).toBe(taskData.description);
      expect(response.body.data.status).toBe(taskData.status);
    });

    it('should create task with default status when not provided', async () => {
      const taskData = {
        title: 'Task without status'
      };

      const response = await request(app)
        .post('/api/tasks')
        .send(taskData);

      expect(response.status).toBe(201);
      expect(response.body.data.status).toBe('pending');
    });

    it('should reject task without title', async () => {
      const response = await request(app)
        .post('/api/tasks')
        .send({ description: 'No title' });

      expect(response.status).toBe(400);
      expect(response.body.success).toBe(false);
    });

    it('should reject task with empty title', async () => {
      const response = await request(app)
        .post('/api/tasks')
        .send({ title: '   ' });

      expect(response.status).toBe(400);
    });
  });

  describe('GET /api/tasks', () => {
    it('should fetch all tasks', async () => {
      // 创建一些测试数据
      await request(app).post('/api/tasks').send({ title: 'Task 1' });
      await request(app).post('/api/tasks').send({ title: 'Task 2' });

      const response = await request(app).get('/api/tasks');
      expect(response.status).toBe(200);
      expect(response.body.success).toBe(true);
      expect(Array.isArray(response.body.data)).toBe(true);
      expect(response.body.data.length).toBeGreaterThanOrEqual(2);
    });

    it('should filter tasks by status', async () => {
      await request(app).post('/api/tasks').send({ title: 'Pending Task', status: 'pending' });
      await request(app).post('/api/tasks').send({ title: 'Completed Task', status: 'completed' });

      const response = await request(app).get('/api/tasks?status=completed');
      expect(response.status).toBe(200);
      expect(response.body.data.every(t => t.status === 'completed')).toBe(true);
    });
  });

  describe('GET /api/tasks/:id', () => {
    it('should fetch a single task by id', async () => {
      const createResponse = await request(app)
        .post('/api/tasks')
        .send({ title: 'Specific Task', description: 'Find me!' });

      const taskId = createResponse.body.data.id;

      const response = await request(app).get(`/api/tasks/${taskId}`);
      expect(response.status).toBe(200);
      expect(response.body.data.id).toBe(taskId);
      expect(response.body.data.title).toBe('Specific Task');
    });

    it('should return 404 for non-existent task', async () => {
      const response = await request(app).get('/api/tasks/non-existent-id');
      expect(response.status).toBe(404);
      expect(response.body.success).toBe(false);
    });
  });

  describe('PUT /api/tasks/:id', () => {
    it('should update a task', async () => {
      const createResponse = await request(app)
        .post('/api/tasks')
        .send({ title: 'Original Title', status: 'pending' });

      const taskId = createResponse.body.data.id;

      const updateResponse = await request(app)
        .put(`/api/tasks/${taskId}`)
        .send({ title: 'Updated Title', status: 'completed' });

      expect(updateResponse.status).toBe(200);
      expect(updateResponse.body.data.title).toBe('Updated Title');
      expect(updateResponse.body.data.status).toBe('completed');
    });

    it('should reject invalid status values', async () => {
      const createResponse = await request(app)
        .post('/api/tasks')
        .send({ title: 'Task' });

      const taskId = createResponse.body.data.id;

      const response = await request(app)
        .put(`/api/tasks/${taskId}`)
        .send({ status: 'invalid_status' });

      expect(response.status).toBe(400);
    });

    it('should return 404 for non-existent task', async () => {
      const response = await request(app)
        .put('/api/tasks/non-existent-id')
        .send({ title: 'Updated' });

      expect(response.status).toBe(404);
    });
  });

  describe('DELETE /api/tasks/:id', () => {
    it('should delete a task', async () => {
      const createResponse = await request(app)
        .post('/api/tasks')
        .send({ title: 'To be deleted' });

      const taskId = createResponse.body.data.id;

      const deleteResponse = await request(app).delete(`/api/tasks/${taskId}`);
      expect(deleteResponse.status).toBe(200);
      expect(deleteResponse.body.success).toBe(true);

      // 验证任务已删除
      const getResponse = await request(app).get(`/api/tasks/${taskId}`);
      expect(getResponse.status).toBe(404);
    });

    it('should return 404 for non-existent task', async () => {
      const response = await request(app).delete('/api/tasks/non-existent-id');
      expect(response.status).toBe(404);
    });
  });

  describe('GET /api/tasks/stats/count', () => {
    it('should return task statistics', async () => {
      await request(app).post('/api/tasks').send({ title: 'Task 1', status: 'pending' });
      await request(app).post('/api/tasks').send({ title: 'Task 2', status: 'completed' });
      await request(app).post('/api/tasks').send({ title: 'Task 3', status: 'completed' });

      const response = await request(app).get('/api/tasks/stats/count');
      expect(response.status).toBe(200);
      expect(response.body.data).toHaveProperty('total', 3);
      expect(response.body.data).toHaveProperty('pending', 1);
      expect(response.body.data).toHaveProperty('completed', 2);
      expect(response.body.data).toHaveProperty('in_progress', 0);
    });
  });

  describe('404 Handler', () => {
    it('should return 404 for unknown routes', async () => {
      const response = await request(app).get('/api/unknown');
      expect(response.status).toBe(404);
      expect(response.body).toHaveProperty('error', 'Route not found');
    });
  });
});

