import axios from 'axios';

const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:3000/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json'
  }
});

export const taskApi = {
  // 获取所有任务
  getAll(params = {}) {
    return api.get('/tasks', { params });
  },

  // 获取单个任务
  getById(id) {
    return api.get(`/tasks/${id}`);
  },

  // 创建任务
  create(taskData) {
    return api.post('/tasks', taskData);
  },

  // 更新任务
  update(id, updates) {
    return api.put(`/tasks/${id}`, updates);
  },

  // 删除任务
  delete(id) {
    return api.delete(`/tasks/${id}`);
  },

  // 获取统计
  getStats() {
    return api.get('/tasks/stats/count');
  }
};

export default api;

import { useState, useEffect, useCallback } from 'react';
import { taskApi } from '../services/taskApi';

const STATUS_FILTERS = {
  ALL: 'all',
  PENDING: 'pending',
  COMPLETED: 'completed'
};

export function useTasks() {
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [filter, setFilter] = useState(STATUS_FILTERS.ALL);
  const [stats, setStats] = useState({ total: 0, pending: 0, completed: 0, in_progress: 0 });

  // 获取任务列表
  const fetchTasks = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const params = filter !== STATUS_FILTERS.ALL ? { status: filter } : {};
      const response = await taskApi.getAll(params);
      setTasks(response.data.data);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch tasks');
    } finally {
      setLoading(false);
    }
  }, [filter]);

  // 获取统计数据
  const fetchStats = useCallback(async () => {
    try {
      const response = await taskApi.getStats();
      setStats(response.data.data);
    } catch (err) {
      console.error('Failed to fetch stats:', err);
    }
  }, []);

  // 创建任务
  const createTask = useCallback(async (title, description = '') => {
    try {
      const response = await taskApi.create({ title, description });
      setTasks(prev => [response.data.data, ...prev]);
      await fetchStats();
      return { success: true, data: response.data.data };
    } catch (err) {
      return {
        success: false,
        error: err.response?.data?.error || 'Failed to create task'
      };
    }
  }, [fetchStats]);

  // 更新任务
  const updateTask = useCallback(async (id, updates) => {
    try {
      const response = await taskApi.update(id, updates);
      setTasks(prev => prev.map(task =>
        task.id === id ? response.data.data : task
      ));
      await fetchStats();
      return { success: true, data: response.data.data };
    } catch (err) {
      return {
        success: false,
        error: err.response?.data?.error || 'Failed to update task'
      };
    }
  }, [fetchStats]);

  // 删除任务
  const deleteTask = useCallback(async (id) => {
    try {
      await taskApi.delete(id);
      setTasks(prev => prev.filter(task => task.id !== id));
      await fetchStats();
      return { success: true };
    } catch (err) {
      return {
        success: false,
        error: err.response?.data?.error || 'Failed to delete task'
      };
    }
  }, [fetchStats]);

  // 切换任务完成状态
  const toggleTaskStatus = useCallback(async (task) => {
    const newStatus = task.status === 'completed' ? 'pending' : 'completed';
    return updateTask(task.id, { status: newStatus });
  }, [updateTask]);

  // 初始加载
  useEffect(() => {
    fetchTasks();
    fetchStats();
  }, [fetchTasks, fetchStats]);

  return {
    tasks,
    loading,
    error,
    filter,
    setFilter,
    stats,
    fetchTasks,
    createTask,
    updateTask,
    deleteTask,
    toggleTaskStatus,
    STATUS_FILTERS
  };
}

import React from 'react';

const TaskCheckbox = ({ checked, onChange, disabled = false }) => {
  return (
    <button
      type="button"
      role="checkbox"
      aria-checked={checked}
      onClick={() => !disabled && onChange(!checked)}
      disabled={disabled}
      style={{
        width: '24px',
        height: '24px',
        border: `2px solid ${checked ? '#3B82F6' : '#D1D5DB'}`,
        borderRadius: '6px',
        backgroundColor: checked ? '#3B82F6' : '#FFFFFF',
        cursor: disabled ? 'not-allowed' : 'pointer',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        transition: 'all 0.2s ease',
        flexShrink: 0,
        opacity: disabled ? 0.6 : 1
      }}
      onMouseEnter={(e) => {
        if (!disabled) {
          e.target.style.borderColor = '#3B82F6';
        }
      }}
      onMouseLeave={(e) => {
        if (!disabled) {
          e.target.style.borderColor = checked ? '#3B82F6' : '#D1D5DB';
        }
      }}
    >
      {checked && (
        <svg
          width="14"
          height="14"
          viewBox="0 0 24 24"
          fill="none"
          stroke="white"
          strokeWidth="3"
          strokeLinecap="round"
          strokeLinejoin="round"
        >
          <polyline points="20 6 9 17 4 12"></polyline>
        </svg>
      )}
    </button>
  );
};

export default TaskCheckbox;

import React, { useState } from 'react';
import { FaEdit, FaTrash } from 'react-icons/fa';

const TaskActions = ({ onEdit, onDelete, disabled = false }) => {
  const [showConfirm, setShowConfirm] = useState(false);

  const handleDelete = () => {
    if (showConfirm) {
      onDelete();
      setShowConfirm(false);
    } else {
      setShowConfirm(true);
    }
  };

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: '8px',
        flexShrink: 0
      }}
    >
      {showConfirm && (
        <div
          style={{
            position: 'absolute',
            right: '60px',
            background: 'white',
            border: '1px solid #E5E7EB',
            borderRadius: '8px',
            padding: '8px 12px',
            boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
            fontSize: '12px',
            color: '#6B7280',
            zIndex: 10
          }}
        >
          确认删除?
          <div
            style={{
              display: 'inline-flex',
              marginLeft: '8px',
              gap: '4px'
            }}
          >
            <button
              onClick={() => setShowConfirm(false)}
              style={{
                border: 'none',
                background: 'transparent',
                color: '#3B82F6',
                cursor: 'pointer',
                fontSize: '12px'
              }}
            >
              取消
            </button>
            <span style={{ color: '#9CA3AF' }}>|</span>
            <button
              onClick={handleDelete}
              style={{
                border: 'none',
                background: 'transparent',
                color: '#EF4444',
                cursor: 'pointer',
                fontSize: '12px'
              }}
            >
              删除
            </button>
          </div>
        </div>
      )}

      <button
        type="button"
        onClick={onEdit}
        disabled={disabled}
        aria-label="编辑任务"
        title="编辑"
        style={{
          background: 'transparent',
          border: 'none',
          cursor: disabled ? 'not-allowed' : 'pointer',
          color: '#6B7280',
          padding: '8px',
          borderRadius: '6px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          opacity: disabled ? 0.4 : 1,
          transition: 'background-color 0.2s, color 0.2s'
        }}
        onMouseEnter={(e) => {
          if (!disabled) {
            e.target.style.backgroundColor = '#F3F4F6';
            e.target.style.color = '#3B82F6';
          }
        }}
        onMouseLeave={(e) => {
          if (!disabled) {
            e.target.style.backgroundColor = 'transparent';
            e.target.style.color = '#6B7280';
          }
        }}
      >
        <FaEdit size={14} />
      </button>

      <button
        type="button"
        onClick={handleDelete}
        disabled={disabled}
        aria-label="删除任务"
        title="删除"
        style={{
          background: 'transparent',
          border: 'none',
          cursor: disabled ? 'not-allowed' : 'pointer',
          color: '#6B7280',
          padding: '8px',
          borderRadius: '6px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          opacity: disabled ? 0.4 : 1,
          transition: 'background-color 0.2s, color 0.2s'
        }}
        onMouseEnter={(e) => {
          if (!disabled) {
            e.target.style.backgroundColor = '#FEF2F2';
            e.target.style.color = '#EF4444';
          }
        }}
        onMouseLeave={(e) => {
          if (!disabled) {
            e.target.style.backgroundColor = 'transparent';
            e.target.style.color = '#6B7280';
          }
        }}
      >
        <FaTrash size={14} />
      </button>
    </div>
  );
};

export default TaskActions;

import React, { useState } from 'react';
import TaskCheckbox from './TaskCheckbox';
import TaskActions from './TaskActions';

const TaskItem = ({ task, onToggle, onEdit, onDelete }) => {
  const [isHovered, setIsHovered] = useState(false);

  const isCompleted = task.status === 'completed';

  return (
    <div
      role="listitem"
      aria-label={`任务: ${task.title}, 状态: ${isCompleted ? '已完成' : '待完成'}`}
      style={{
        display: 'flex',
        alignItems: 'center',
        padding: '16px',
        borderBottom: '1px solid #E5E7EB',
        backgroundColor: isHovered ? '#F9FAFB' : '#FFFFFF',
        transition: 'background-color 0.15s ease',
        minHeight: '64px',
        gap: '12px'
      }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <TaskCheckbox
        checked={isCompleted}
        onChange={() => onToggle(task)}
      />

      <div
        style={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          minWidth: 0
        }}
      >
        <div
          style={{
            fontSize: '16px',
            lineHeight: '24px',
            fontWeight: '400',
            color: isCompleted ? '#9CA3AF' : '#111827',
            textDecoration: isCompleted ? 'line-through' : 'none',
            wordBreak: 'break-word'
          }}
        >
          {task.title}
        </div>
        {task.description && (
          <div
            style={{
              fontSize: '14px',
              lineHeight: '20px',
              color: '#6B7280',
              marginTop: '4px',
              wordBreak: 'break-word'
            }}
          >
            {task.description}
          </div>
        )}
      </div>

      <TaskActions
        onEdit={() => onEdit(task)}
        onDelete={() => onDelete(task.id)}
        disabled={isCompleted}
        style={{ opacity: isHovered ? 1 : 0.4 }}
      />
    </div>
  );
};

export default TaskItem;

import React from 'react';
import { STATUS_FILTERS } from '../hooks/useTasks';

const FilterBar = ({ filter, onFilterChange }) => {
  const filters = [
    { key: STATUS_FILTERS.ALL, label: '全部' },
    { key: STATUS_FILTERS.PENDING, label: '待完成' },
    { key: STATUS_FILTERS.COMPLETED, label: '已完成' }
  ];

  return (
    <div
      role="tablist"
      aria-label="任务过滤器"
      style={{
        display: 'flex',
        gap: '8px',
        borderBottom: '1px solid #E5E7EB',
        padding: '0 16px',
        marginBottom: '16px'
      }}
    >
      {filters.map(({ key, label }) => (
        <button
          key={key}
          role="tab"
          aria-selected={filter === key}
          onClick={() => onFilterChange(key)}
          style={{
            flex: 1,
            background: 'transparent',
            border: 'none',
            borderBottom: filter === key ? '2px solid #3B82F6' : '2px solid transparent',
            padding: '12px 8px',
            fontSize: '15px',
            fontWeight: '500',
            color: filter === key ? '#3B82F6' : '#6B7280',
            cursor: 'pointer',
            transition: 'all 0.2s ease',
            outline: 'none',
            marginBottom: '-1px'
          }}
          onMouseEnter={(e) => {
            if (filter !== key) {
              e.target.style.color = '#3B82F6';
            }
          }}
          onMouseLeave={(e) => {
            if (filter !== key) {
              e.target.style.color = '#6B7280';
            }
          }}
        >
          {label}
        </button>
      ))}
    </div>
  );
};

export default FilterBar;

import React, { useState } from 'react';

const TaskInput = ({ onAddTask, disabled = false }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!title.trim() || isSubmitting || disabled) return;

    setIsSubmitting(true);
    try {
      const result = await onAddTask(title.trim(), description.trim());
      if (result.success) {
        setTitle('');
        setDescription('');
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e);
    }
  };

  return (
    <form
      onSubmit={handleSubmit}
      style={{
        padding: '16px',
        borderBottom: '1px solid #E5E7EB',
        backgroundColor: '#FFFFFF'
      }}
    >
      <div
        style={{
          display: 'flex',
          gap: '8px',
          marginBottom: '8px'
        }}
      >
        <input
          type="text"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="添加新任务..."
          disabled={disabled || isSubmitting}
          aria-label="任务标题"
          required
          maxLength={200}
          style={{
            flex: 1,
            padding: '0 16px',
            height: '44px',
            border: '1px solid #E5E7EB',
            borderRadius: '12px',
            fontSize: '16px',
            color: '#111827',
            outline: 'none',
            transition: 'border-color 0.2s',
            backgroundColor: disabled ? '#F9FAFB' : '#FFFFFF'
          }}
          onFocus={(e) => {
            e.target.style.borderColor = '#3B82F6';
          }}
          onBlur={(e) => {
            e.target.style.borderColor = '#E5E7EB';
          }}
        />
        <button
          type="submit"
          disabled={!title.trim() || isSubmitting || disabled}
          aria-label="添加任务"
          style={{
            padding: '0 24px',
            height: '44px',
            backgroundColor: (!title.trim() || isSubmitting || disabled)
              ? '#9CA3AF'
              : '#3B82F6',
            color: '#FFFFFF',
            border: 'none',
            borderRadius: '12px',
            fontSize: '14px',
            fontWeight: '500',
            cursor: (!title.trim() || isSubmitting || disabled)
              ? 'not-allowed'
              : 'pointer',
            transition: 'background-color 0.2s',
            whiteSpace: 'nowrap'
          }}
          onMouseEnter={(e) => {
            if (!title.trim() || isSubmitting || disabled) return;
            e.target.style.backgroundColor = '#2563EB';
          }}
          onMouseLeave={(e) => {
            if (!title.trim() || isSubmitting || disabled) return;
            e.target.style.backgroundColor = '#3B82F6';
          }}
        >
          {isSubmitting ? '...' : '添加'}
        </button>
      </div>

      <input
        type="text"
        value={description}
        onChange={(e) => setDescription(e.target.value)}
        placeholder="添加描述（可选）"
        disabled={disabled || isSubmitting}
        aria-label="任务描述"
        maxLength={500}
        style={{
          width: '100%',
          padding: '0 16px',
          height: '36px',
          border: '1px solid #E5E7EB',
          borderRadius: '8px',
          fontSize: '14px',
          color: '#111827',
          outline: 'none',
          transition: 'border-color 0.2s',
          backgroundColor: disabled ? '#F9FAFB' : '#FFFFFF',
          marginTop: '8px'
        }}
        onFocus={(e) => {
          e.target.style.borderColor = '#3B82F6';
        }}
        onBlur={(e) => {
          e.target.style.borderColor = '#E5E7EB';
        }}
      />
    </form>
  );
};

export default TaskInput;

import React, { useState, useEffect } from 'react';

const EditTaskModal = ({ task, onSave, onClose }) => {
  const [title, setTitle] = useState(task.title);
  const [description, setDescription] = useState(task.description || '');
  const [status, setStatus] = useState(task.status);

  useEffect(() => {
    setTitle(task.title);
    setDescription(task.description || '');
    setStatus(task.status);
  }, [task]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!title.trim()) return;
    onSave(task.id, { title: title.trim(), description: description.trim(), status });
  };

  const handleBackdropClick = (e) => {
    if (e.target === e.currentTarget) {
      onClose();
    }
  };

  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-labelledby="edit-task-title"
      onClick={handleBackdropClick}
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: 'rgba(0, 0, 0, 0.5)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 1000,
        padding: '16px'
      }}
    >
      <div
        style={{
          backgroundColor: 'white',
          borderRadius: '16px',
          padding: '24px',
          width: '100%',
          maxWidth: '500px',
          boxShadow: '0 10px 40px rgba(0,0,0,0.2)'
        }}
      >
        <h2
          id="edit-task-title"
          style={{
            margin: '0 0 20px 0',
            fontSize: '20px',
            fontWeight: '600',
            color: '#111827'
          }}
        >
          编辑任务
        </h2>

        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: '16px' }}>
            <label
              htmlFor="edit-title"
              style={{
                display: 'block',
                marginBottom: '8px',
                fontSize: '14px',
                fontWeight: '500',
                color: '#111827'
              }}
            >
              标题 <span style={{ color: '#EF4444' }}>*</span>
            </label>
            <input
              id="edit-title"
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              required
              maxLength={200}
              style={{
                width: '100%',
                padding: '12px',
                border: '1px solid #E5E7EB',
                borderRadius: '8px',
                fontSize: '16px',
                outline: 'none',
                boxSizing: 'border-box'
              }}
              onFocus={(e) => {
                e.target.style.borderColor = '#3B82F6';
              }}
              onBlur={(e) => {
                e.target.style.borderColor = '#E5E7EB';
              }}
            />
          </div>

          <div style={{ marginBottom: '16px' }}>
            <label
              htmlFor="edit-description"
              style={{
                display: 'block',
                marginBottom: '8px',
                fontSize: '14px',
                fontWeight: '500',
                color: '#111827'
              }}
            >
              描述
            </label>
            <textarea
              id="edit-description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              maxLength={500}
              rows={3}
              style={{
                width: '100%',
                padding: '12px',
                border: '1px solid #E5E7EB',
                borderRadius: '8px',
                fontSize: '16px',
                outline: 'none',
                resize: 'vertical',
                minHeight: '80px',
                boxSizing: 'border-box'
              }}
              onFocus={(e) => {
                e.target.style.borderColor = '#3B82F6';
              }}
              onBlur={(e) => {
                e.target.style.borderColor = '#E5E7EB';
              }}
            />
          </div>

          <div style={{ marginBottom: '24px' }}>
            <label
              htmlFor="edit-status"
              style={{
                display: 'block',
                marginBottom: '8px',
                fontSize: '14px',
                fontWeight: '500',
                color: '#111827'
              }}
            >
              状态
            </label>
            <select
              id="edit-status"
              value={status}
              onChange={(e) => setStatus(e.target.value)}
              style={{
                width: '100%',
                padding: '12px',
                border: '1px solid #E5E7EB',
                borderRadius: '8px',
                fontSize: '16px',
                outline: 'none',
                backgroundColor: 'white',
                boxSizing: 'border-box'
              }}
            >
              <option value="pending">待完成</option>
              <option value="in_progress">进行中</option>
              <option value="completed">已完成</option>
            </select>
          </div>

          <div
            style={{
              display: 'flex',
              justifyContent: 'flex-end',
              gap: '12px'
            }}
          >
            <button
              type="button"
              onClick={onClose}
              style={{
                padding: '10px 20px',
                border: '1px solid #E5E7EB',
                borderRadius: '8px',
                backgroundColor: 'white',
                color: '#6B7280',
                fontSize: '14px',
                fontWeight: '500',
                cursor: 'pointer'
              }}
            >
              取消
            </button>
            <button
              type="submit"
              disabled={!title.trim()}
              style={{
                padding: '10px 24px',
                border: 'none',
                borderRadius: '8px',
                backgroundColor: !title.trim() ? '#9CA3AF' : '#3B82F6',
                color: 'white',
                fontSize: '14px',
                fontWeight: '500',
                cursor: !title.trim() ? 'not-allowed' : 'pointer'
              }}
            >
              保存
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTaskModal;

