module.exports = {
  testEnvironment: 'jsdom',
  setupFilesAfterEnv: ['<rootDir>/src/setupTests.js'],
  moduleNameMapper: {
    '\\.(css|less|scss|sass)$': 'identity-obj-proxy',
    '^\\/(.*)$': '<rootDir>/src/$1'
  },
  testMatch: [
    '<rootDir>/src/**/*.{test,spec}.{js,jsx,ts,tsx}'
  ],
  transform: {
    '^.+\\.(js|jsx)$': 'babel-jest'
  }
};

const presets = [
  ['@babel/preset-env', { targets: { node: 'current' } }],
  ['@babel/preset-react', { runtime: 'automatic' }]
];

module.exports = { presets };

import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { describe, it, expect, vi, beforeEach } from 'vitest';
import TaskCheckbox from '../components/TaskCheckbox';

describe('TaskCheckbox', () => {
  it('renders unchecked checkbox', () => {
    const onChange = vi.fn();
    render(<TaskCheckbox checked={false} onChange={onChange} />);

    const button = screen.getByRole('checkbox');
    expect(button).toHaveAttribute('aria-checked', 'false');
  });

  it('renders checked checkbox', () => {
    const onChange = vi.fn();
    render(<TaskCheckbox checked={true} onChange={onChange} />);

    const button = screen.getByRole('checkbox');
    expect(button).toHaveAttribute('aria-checked', 'true');
  });

  it('calls onChange when clicked', async () => {
    const onChange = vi.fn();
    render(<TaskCheckbox checked={false} onChange={onChange} />);

    const button = screen.getByRole('button');
    await userEvent.click(button);

    expect(onChange).toHaveBeenCalledWith(true);
  });

  it('does not call onChange when disabled', async () => {
    const onChange = vi.fn();
    render(<TaskCheckbox checked={false} onChange={onChange} disabled={true} />);

    const button = screen.getByRole('button');
    expect(button).toBeDisabled();

    await userEvent.click(button);
    expect(onChange).not.toHaveBeenCalled();
  });
});

import { render, screen, fireEvent } from '@testing-library/react';
import { describe, it, expect, vi } from 'vitest';
import FilterBar from '../components/FilterBar';

const mockFilters = {
  ALL: 'all',
  PENDING: 'pending',
  COMPLETED: 'completed'
};

describe('FilterBar', () => {
  it('renders all filter buttons', () => {
    const onFilterChange = vi.fn();
    render(<FilterBar filter={mockFilters.ALL} onFilterChange={onFilterChange} />);

    expect(screen.getByText('全部')).toBeInTheDocument();
    expect(screen.getByText('待完成')).toBeInTheDocument();
    expect(screen.getByText('已完成')).toBeInTheDocument();
  });

  it('highlights active filter', () => {
    const onFilterChange = vi.fn();
    render(<FilterBar filter={mockFilters.PENDING} onFilterChange={onFilterChange} />);

    const pendingButton = screen.getByText('待完成');
    expect(pendingButton).toHaveAttribute('aria-selected', 'true');
    expect(pendingButton.style.color).toBe('rgb(59, 130, 246)'); // #3B82F6
  });

  it('calls onFilterChange when clicking a filter', async () => {
    const onFilterChange = vi.fn();
    render(<FilterBar filter={mockFilters.ALL} onFilterChange={onFilterChange} />);

    const completedButton = screen.getByText('已完成');
    await fireEvent.click(completedButton);

    expect(onFilterChange).toHaveBeenCalledWith(mockFilters.COMPLETED);
  });

  it('renders with correct tablist role for accessibility', () => {
    const onFilterChange = vi.fn();
    render(<FilterBar filter={mockFilters.ALL} onFilterChange={onFilterChange} />);

    const tablist = screen.getByRole('tablist');
    expect(tablist).toHaveAttribute('aria-label', '任务过滤器');
  });
});

import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { describe, it, expect, vi } from 'vitest';
import TaskInput from '../components/TaskInput';

describe('TaskInput', () => {
  it('renders input field and add button', () => {
    const onAddTask = vi.fn();
    render(<TaskInput onAddTask={onAddTask} />);

    expect(screen.getByPlaceholderText('添加新任务...')).toBeInTheDocument();
    expect(screen.getByRole('button', { name: '添加任务' })).toBeInTheDocument();
  });

  it('disables add button when title is empty', () => {
    const onAddTask = vi.fn();
    render(<TaskInput onAddTask={onAddTask} />);

    const addButton = screen.getByRole('button', { name: '添加任务' });
    expect(addButton).toBeDisabled();
  });

  it('enables add button when title is entered', async () => {
    const onAddTask = vi.fn().mockResolvedValue({ success: true });
    render(<TaskInput onAddTask={onAddTask} />);

    const input = screen.getByPlaceholderText('添加新任务...');
    await userEvent.type(input, 'New task');

    const addButton = screen.getByRole('button', { name: '添加任务' });
    expect(addButton).not.toBeDisabled();
  });

  it('calls onAddTask with title and description when form submitted', async () => {
    const onAddTask = vi.fn().mockResolvedValue({ success: true });
    render(<TaskInput onAddTask={onAddTask} />);

    const titleInput = screen.getByPlaceholderText('添加新任务...');
    const descInput = screen.getByPlaceholderText('添加描述（可选）');
    const addButton = screen.getByRole('button', { name: '添加任务' });

    await userEvent.type(titleInput, 'Test task');
    await userEvent.type(descInput, 'Test description');
    await userEvent.click(addButton);

    await waitFor(() => {
      expect(onAddTask).toHaveBeenCalledWith('Test task', 'Test description');
    });
  });

  it('clears inputs after successful submission', async () => {
    const onAddTask = vi.fn().mockResolvedValue({ success: true });
    render(<TaskInput onAddTask={onAddTask} />);

    const titleInput = screen.getByPlaceholderText('添加新任务...');
    const descInput = screen.getByPlaceholderText('添加描述（可选）');
    const addButton = screen.getByRole('button', { name: '添加任务' });

    await userEvent.type(titleInput, 'Test task');
    await userEvent.type(descInput, 'Test description');
    await userEvent.click(addButton);

    await waitFor(() => {
      expect(titleInput).toHaveValue('');
      expect(descInput).toHaveValue('');
    });
  });

  it('shows loading state when submitting', async () => {
    const onAddTask = vi.fn(() => new Promise(resolve => setTimeout(resolve, 100)));
    render(<TaskInput onAddTask={onAddTask} />);

    const titleInput = screen.getByPlaceholderText('添加新任务...');
    await userEvent.type(titleInput, 'Test task');

    const addButton = screen.getByRole('button', { name: '添加任务' });
    await userEvent.click(addButton);

    expect(addButton).toHaveTextContent('...');
    expect(addButton).toBeDisabled();
  });

  it('disables inputs when disabled prop is true', () => {
    const onAddTask = vi.fn();
    render(<TaskInput onAddTask={onAddTask} disabled={true} />);

    expect(screen.getByPlaceholderText('添加新任务...')).toBeDisabled();
    expect(screen.getByPlaceholderText('添加描述（可选）')).toBeDisabled();
    expect(screen.getByRole('button', { name: '添加任务' })).toBeDisabled();
  });

  it('submits on Enter key press', async () => {
    const onAddTask = vi.fn().mockResolvedValue({ success: true });
    render(<TaskInput onAddTask={onAddTask} />);

    const titleInput = screen.getByPlaceholderText('添加新任务...');
    await userEvent.type(titleInput, 'Test task{Enter}');

    await waitFor(() => {
      expect(onAddTask).toHaveBeenCalledWith('Test task', '');
    });
  });
});

