import { render, screen, waitFor, within } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { describe, it, expect, vi, beforeEach } from 'jest';
import App from '../App';

// Mock the task API module
vi.mock('../services/taskApi', () => ({
  taskApi: {
    getAll: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    delete: vi.fn(),
    getStats: vi.fn()
  }
}));

import { taskApi } from '../services/taskApi';

const mockTasks = [
  {
    id: '1',
    title: 'Task 1',
    description: 'Description 1',
    status: 'pending',
    created_at: '2026-03-10T00:00:00.000Z',
    updated_at: '2026-03-10T00:00:00.000Z'
  },
  {
    id: '2',
    title: 'Task 2',
    description: '',
    status: 'completed',
    created_at: '2026-03-10T00:00:00.000Z',
    updated_at: '2026-03-10T00:00:00.000Z'
  }
];

const mockStats = {
  total: 2,
  pending: 1,
  completed: 1,
  in_progress: 0
};

describe('App Integration', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    taskApi.getAll.mockResolvedValue({ data: { data: mockTasks } });
    taskApi.getStats.mockResolvedValue({ data: { data: mockStats } });
    taskApi.create.mockResolvedValue({
      data: { data: { id: '3', title: 'New Task', status: 'pending' } }
    });
    taskApi.update.mockResolvedValue({
      data: { data: { ...mockTasks[0], status: 'completed' } }
    });
    taskApi.delete.mockResolvedValue({ data: {} });
  });

  it('renders the app with header', async () => {
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText(/待办事项/)).toBeInTheDocument();
    });
  });

  it('loads and displays tasks', async () => {
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText('Task 1')).toBeInTheDocument();
      expect(screen.getByText('Task 2')).toBeInTheDocument();
    });
  });

  it('displays filter buttons', async () => {
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText('全部')).toBeInTheDocument();
      expect(screen.getByText('待完成')).toBeInTheDocument();
      expect(screen.getByText('已完成')).toBeInTheDocument();
    });
  });

  it('shows stats in footer', async () => {
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText(/1 待完成 · 1 已完成/)).toBeInTheDocument();
    });
  });

  it('creates a new task', async () => {
    const user = userEvent.setup();
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText('Task 1')).toBeInTheDocument();
    });

    const titleInput = screen.getByPlaceholderText('添加新任务...');
    const addButton = screen.getByRole('button', { name: '添加任务' });

    await user.type(titleInput, 'New Task');
    await user.click(addButton);

    await waitFor(() => {
      expect(taskApi.create).toHaveBeenCalledWith({ title: 'New Task', description: '' });
    });
  });

  it('toggles task status', async () => {
    const user = userEvent.setup();
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText('Task 1')).toBeInTheDocument();
    });

    // Find the task item
    const taskItem = screen.getByText('Task 1').closest('[role="listitem"]');
    const checkbox = within(taskItem).getByRole('checkbox');

    await user.click(checkbox);

    await waitFor(() => {
      expect(taskApi.update).toHaveBeenCalledWith('1', { status: 'completed' });
    });
  });

  it('opens edit modal when edit button clicked', async () => {
    const user = userEvent.setup();
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText('Task 1')).toBeInTheDocument();
    });

    const taskItem = screen.getByText('Task 1').closest('[role="listitem"]');
    const editButton = within(taskItem).getByLabelText('编辑任务');

    await user.click(editButton);

    await waitFor(() => {
      expect(screen.getByText('编辑任务')).toBeInTheDocument();
      expect(screen.getByDisplayValue('Task 1')).toBeInTheDocument();
    });
  });

  it('deletes a task when delete confirmed', async () => {
    const user = userEvent.setup();
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText('Task 1')).toBeInTheDocument();
    });

    const taskItem = screen.getByText('Task 1').closest('[role="listitem"]');
    const deleteButton = within(taskItem).getByLabelText('删除任务');

    await user.click(deleteButton);

    // Confirm deletion
    const confirmDelete = await screen.findByText('删除');
    await user.click(confirmDelete);

    await waitFor(() => {
      expect(taskApi.delete).toHaveBeenCalledWith('1');
    });
